SQL-2. DML — StarRocks 가이드 SQL-2. DML — INSERT / UPDATE / DELETE INSERT -- VALUES
INSERT INTO mart.orders VALUES (1, 100, 'paid', 12345.00, NOW());

-- 다중 행
INSERT INTO mart.orders VALUES
  (2, 100, 'paid', 5000, NOW()),
  (3, 101, 'pending', 200, NOW());

-- INSERT INTO ... SELECT (가장 흔함)
INSERT INTO mart.orders
SELECT * FROM hive_prod.dwh.orders WHERE dt = '2026-05-07';

-- 외부 카탈로그로도 INSERT (Hive v3.2+, Iceberg v3.x)
INSERT INTO hive_prod.dwh.summary SELECT ... ;

-- INSERT OVERWRITE (파티션 단위 덮어쓰기)
INSERT OVERWRITE mart.orders PARTITION (p20260507)
SELECT * FROM stage.orders WHERE updated_at::date = '2026-05-07';

-- 라벨 (재시도 안전)
INSERT INTO mart.orders WITH LABEL ord_20260507_001 SELECT ...; UPDATE (Primary Key 테이블에 한해 직접 가능) UPDATE mart.orders SET status = 'refunded' WHERE order_id = 1;

UPDATE mart.orders
SET amount = amount * 0.9
WHERE updated_at >= '2026-05-01' AND status = 'paid';

-- JOIN 조건으로 갱신
UPDATE mart.orders o
SET status = 'closed'
FROM stage.cancel s
WHERE o.order_id = s.order_id; Duplicate / Aggregate / Unique 모델은 직접 UPDATE 불가. UPSERT/REPLACE 적재로 대신. DELETE DELETE FROM mart.orders WHERE updated_at < '2026-01-01';

-- PK 테이블이면 일반 DELETE 가능. 비-PK 테이블은 파티션 단위 권장.
ALTER TABLE mart.orders DROP PARTITION p20260101; CTE / WITH WITH paid AS (
  SELECT user_id, sum(amount) amt FROM mart.orders WHERE status='paid' GROUP BY user_id
),
ranked AS (
  SELECT user_id, amt, rank() OVER (ORDER BY amt DESC) rk FROM paid
)
SELECT * FROM ranked WHERE rk <= 100; EXPLAIN / EXPLAIN ANALYZE EXPLAIN  SELECT count(*) FROM mart.orders WHERE updated_at >= '2026-05-07';
EXPLAIN ANALYZE SELECT ...;
EXPLAIN ALL SELECT ...;     -- 모든 단계 (parser, analyzer, optimizer) SHOW · DESCRIBE DESCRIBE mart.orders;
SHOW CREATE TABLE mart.orders;
SHOW PARTITIONS FROM mart.orders;
SHOW INDEX FROM mart.orders;
SHOW PROCESSLIST;
SHOW VARIABLES LIKE '%mv%';
SHOW LOAD WHERE STATE != 'FINISHED'; 클러스터 적용 노트 대용량 백필은 INSERT OVERWRITE 를 파티션 단위로 끊어 진행. 한 번에 전체 OVERWRITE는 위험. UPDATE/DELETE는 PK 테이블 전용. ETL 업스트림에서 변경 분만 보내고 PK 테이블이 받아주는 패턴이 안전·효율적. Async MV가 있는 베이스 테이블에 큰 DML이 일어나면 MV가 무효화될 수 있음 — 의도적인 큰 변경 후엔 REFRESH MATERIALIZED VIEW 를 명시적으로.

SQL-3. 날짜·시간 함수 — StarRocks 가이드 SQL-3. 날짜·시간 함수 현재 시각 함수 의미 NOW() / CURRENT_TIMESTAMP() 현재 DATETIME CURDATE() / CURRENT_DATE() 현재 DATE UTC_TIMESTAMP() UTC 시각 UNIX_TIMESTAMP([dt]) 유닉스 epoch 초 truncate / 형변환 -- 핵심: date_trunc는 파티션 키와 같이 가장 자주 쓰는 함수
SELECT date_trunc('day',  now());     -- 2026-05-07 00:00:00
SELECT date_trunc('hour', now());
SELECT date_trunc('month', now());
SELECT date_trunc('week', now());     -- 월요일 시작

-- 형변환
SELECT CAST('2026-05-07' AS DATE);
SELECT CAST('2026-05-07 10:00:00' AS DATETIME);
SELECT FROM_UNIXTIME(1746547200);
SELECT UNIX_TIMESTAMP('2026-05-07 10:00:00'); 차이 / 가감 SELECT DATEDIFF('2026-05-07','2026-05-01');        -- 6 (일 차이)
SELECT DATE_DIFF('hour', t1, t2);                  -- 단위 명시
SELECT TIMESTAMPDIFF(SECOND, t1, t2);
SELECT DATE_ADD('2026-05-07', INTERVAL 7 DAY);
SELECT DATE_SUB(now(), INTERVAL 1 HOUR);
SELECT now() + INTERVAL 30 MINUTE; 포맷 SELECT DATE_FORMAT(now(), '%Y-%m-%d %H:%i:%s');     -- 2026-05-07 10:00:00
SELECT DATE_FORMAT(now(), '%Y%m%d');                -- 20260507
SELECT STR_TO_DATE('07/05/2026','%d/%m/%Y'); 추출 함수 의미 YEAR(dt) / MONTH(dt) / DAY(dt) 년/월/일 HOUR(dt) / MINUTE(dt) / SECOND(dt) 시/분/초 DAYOFWEEK(dt) 1=일 ... 7=토 (MySQL 호환) DAYOFYEAR(dt) 해의 며칠째 WEEK(dt) 해의 몇 번째 주 QUARTER(dt) 분기 1~4 EXTRACT(unit FROM dt) 표준 SQL 형식 기간 윈도 -- 마지막 7일
WHERE event_time >= now() - INTERVAL 7 DAY

-- 지난 달
WHERE date_trunc('month', event_time) = date_trunc('month', now() - INTERVAL 1 MONTH)

-- 시간대 변환 (UTC ↔ 로컬)
SELECT CONVERT_TZ('2026-05-07 10:00:00', '+00:00', '+09:00'); 클러스터 적용 노트 파티션 키는 거의 항상 date_trunc('day', ...) 또는 date_trunc('hour', ...) . 시간대는 적재 시점에 통일(보통 KST 또는 UTC). FROM_UNIXTIME · UNIX_TIMESTAMP 는 epoch 기반 적재(예: 모바일 로그)에서 자주 사용. 적재 시 DATETIME으로 통일하면 쿼리가 단순해짐. 대시보드의 "오늘" 필터는 WHERE dt = CURDATE() 가 가장 빠름 — 함수 적용 없이 파티션 키와 일치.

SQL-4. 문자열 함수 — StarRocks 가이드 SQL-4. 문자열 함수 기본 함수 예시 LENGTH(s) / CHAR_LENGTH(s) 바이트 / 문자 길이 UPPER(s) / LOWER(s) 대문자/소문자 TRIM/LTRIM/RTRIM(s) 양쪽/왼쪽/오른쪽 공백 제거 CONCAT(a, b, ...) 이어붙이기 CONCAT_WS(sep, a, b, ...) 구분자 사용 REPLACE(s, from, to) 치환 REVERSE(s) 뒤집기 SUBSTR(s, start[, len]) / SUBSTRING 부분 문자열 (start는 1부터) LEFT(s, n) / RIGHT(s, n) 앞/뒤 n자 LPAD/RPAD(s, len, pad) 패딩 검색 SELECT INSTR('hello world', 'world');     -- 7 (1-base, 0이면 없음)
SELECT POSITION('w' IN 'hello world');
SELECT LOCATE('w', 'hello world');
SELECT 'hello world' LIKE '%world';
SELECT 'hello world' LIKE 'h_llo%'; 정규식 SELECT REGEXP_LIKE(col, '^[A-Z]+$');
SELECT col REGEXP '^[0-9]+$';
SELECT REGEXP_REPLACE(col, '\\s+', ' ');
SELECT REGEXP_EXTRACT(url, '/user/([0-9]+)/', 1);  -- 그룹 1
SELECT REGEXP_EXTRACT_ALL('a1b2c3', '[a-z]([0-9])', 1);  -- ['1','2','3'] 분할 / 결합 SELECT SPLIT('a,b,c', ',');               -- ['a','b','c']
SELECT SPLIT_PART('a,b,c', ',', 2);       -- 'b' (1-base)
SELECT ARRAY_JOIN(ARRAY['a','b','c'], '-'); -- 'a-b-c' JSON 추출 (간이) SELECT GET_JSON_STRING(payload, '$.user.id');
SELECT GET_JSON_INT   (payload, '$.amount');
SELECT GET_JSON_DOUBLE(payload, '$.price');
-- 본격적인 JSON 처리는 SQL-7. JSON 페이지 참조 인코딩 SELECT TO_BASE64('hello');
SELECT FROM_BASE64('aGVsbG8=');
SELECT URL_ENCODE('a b/c?d=1');
SELECT URL_DECODE('a%20b');
SELECT MD5(s);
SELECT SHA2(s, 256);
SELECT HEX(123);  -- '7B' 문자열 ↔ 숫자 SELECT CAST('123' AS BIGINT);
SELECT CAST('1.5' AS DOUBLE);
SELECT FORMAT(12345.678, 2);  -- '12,345.68'
SELECT NULLIF(s, '');         -- 빈 문자열을 NULL로 클러스터 적용 노트 LIKE '%foo%' 가 잦은 컬럼은 N-Gram Bloom 인덱스( 3-2 ) 추가 검토. 운영 로그/메시지 분석에서 정규식이 무겁게 도는 경우, ETL 단계에서 미리 split/extract해 컬럼화하는 게 SR 부하를 크게 줄임.

SQL-8. MySQL 호환성 — StarRocks 가이드 SQL-8. MySQL 호환성 — 비슷하지만 다른 점 StarRocks는 MySQL 와이어 프로토콜을 그대로 사용해 도구 호환성이 매우 높지만, 분석 워크로드를 위해 설계된 SQL 다이얼렉트 이므로 MySQL과는 다음과 같은 차이가 있습니다. DML 주제 MySQL StarRocks UPDATE/DELETE 모든 테이블 Primary Key 테이블에서 일반적으로 가능. 다른 모델은 파티션 단위 변경. 트랜잭션 BEGIN/COMMIT/ROLLBACK 적재 단위(Stream/Routine Load 등)에 트랜잭션 — 다중 문장 트랜잭션은 미지원 INSERT label 없음 중복 방지 label 강력 권장 FK / CHECK / UNIQUE 지원 제약 미강제 (모델 자체로 충돌 방지) DDL 테이블 생성 시 PRIMARY KEY / DUPLICATE KEY / AGGREGATE KEY / UNIQUE KEY 모델을 명시. 파티션·버킷팅·복제본을 거의 항상 함께 정의. 인덱스 종류가 BITMAP / BLOOM / N-GRAM 등 다양 — MySQL B-Tree 인덱스와 의미가 다름. 스토어드 프로시저는 매우 제한적/없음. 데이터 타입 타입 MySQL과 차이 VARCHAR 최대 1MB까지. 길이 제한 표기 가능. TEXT / STRING STRING은 사실상 매우 큰 VARCHAR. JSON 네이티브 JSON 타입 + 풍부한 함수. BITMAP / HLL StarRocks 고유 — UV 분석에 핵심. ARRAY / MAP / STRUCT 네이티브 지원. ENUM / SET 없음 — TINYINT/VARCHAR로 대체. DECIMAL 지원. precision/scale 명시. 자주 다른 문법 -- 1) IFNULL/COALESCE 모두 OK. 단 NULL 비교는 =/!= 대신 IS NULL.

